import{_ as t,N as i,o as l,a as n,e as o,i as r}from"./chunks/framework.DW6Cm6Mn.js";const g=JSON.parse('{"title":"About Vala","description":"Vala is an object-oriented programming language with a self-hosting compiler that generates C code and uses the GObject type system.","frontmatter":{"title":"About Vala","description":"Vala is an object-oriented programming language with a self-hosting compiler that generates C code and uses the GObject type system."},"headers":[],"relativePath":"about/index.md","filePath":"about/index.md"}'),s={name:"about/index.md"};function d(h,a,c,u,p,m){const e=i("PredefinedCtaStack");return l(),n("div",null,[a[0]||(a[0]=o('<h1 id="about-vala" tabindex="-1">About Vala <a class="header-anchor" href="#about-vala" aria-label="Permalink to &quot;About Vala&quot;">​</a></h1><h2 id="what-is-vala" tabindex="-1">What is Vala? <a class="header-anchor" href="#what-is-vala" aria-label="Permalink to &quot;What is Vala?&quot;">​</a></h2><p>Vala is an object-oriented programming language with a self-hosting compiler that generates C code and uses the GObject type system.</p><p>Vala supports modern language features such as:</p><ul><li>Interfaces</li><li>Properties</li><li>Signals</li><li>Foreach statements</li><li>Lambda expressions</li><li>Type inferencing for local variables</li><li>Generics</li><li>Non-null types</li><li>Assisted memory management</li><li>Exception handling</li><li>Type modules (Plugins)</li></ul><h2 id="what-kind-of-language-is-vala" tabindex="-1">What kind of language is Vala? <a class="header-anchor" href="#what-kind-of-language-is-vala" aria-label="Permalink to &quot;What kind of language is Vala?&quot;">​</a></h2><h3 id="productive" tabindex="-1">Productive <a class="header-anchor" href="#productive" aria-label="Permalink to &quot;Productive&quot;">​</a></h3><p>With Vala, you can get up and running quickly, thanks to convenient features like lambda expressions, exception handling, interfaces and generics.</p><h3 id="performant" tabindex="-1">Performant <a class="header-anchor" href="#performant" aria-label="Permalink to &quot;Performant&quot;">​</a></h3><p>Vala code compiles down to fully native binaries.</p><h3 id="statically-typed" tabindex="-1">Statically-Typed <a class="header-anchor" href="#statically-typed" aria-label="Permalink to &quot;Statically-Typed&quot;">​</a></h3><p>Vala helps you write type-safe code without the verbosity, thanks to type inference.</p><h3 id="integrative" tabindex="-1">Integrative <a class="header-anchor" href="#integrative" aria-label="Permalink to &quot;Integrative&quot;">​</a></h3><p>Vala is designed to allow access to existing C libraries, especially GObject-based libraries, without the need for runtime bindings. All that is needed to use a library with Vala is an API file, containing the class and method declarations in Vala syntax. Vala currently comes with bindings for GLib and GTK+ and many others from the GNOME Platform.</p><p>Vala can also be used to create C libraries too.</p><h3 id="familiar" tabindex="-1">Familiar <a class="header-anchor" href="#familiar" aria-label="Permalink to &quot;Familiar&quot;">​</a></h3><p>The syntax of Vala is inspired by C# and Java, so if you have used either of those, you&#39;ll seamlessly adapt to writing Vala code.</p>',17)),r(e)])}const b=t(s,[["render",d]]);export{g as __pageData,b as default};
